1	import mongoose, { Schema, Document, Model } from 'mongoose';
2	import { ITest, IQuestion, IRelatedContent, IMatchingItem } from '../types';
3	import { ENT_QUESTION_TYPES, validateEntQuestion } from '../utils/entQuestion.util';
4	
5	const RelatedContentSchema = new Schema<IRelatedContent>(
6	  {
7	    chapterId: {
8	      type: Schema.Types.ObjectId
9	    },
10	    topicId: {
11	      type: Schema.Types.ObjectId
12	    },
13	    pages: [
14	      {
15	        type: Number,
16	        required: true
17	      }
18	    ],
19	    topicTitle: { type: String, trim: true }
20	  },
21	  { _id: false }
22	);
23	
24	const MatchingItemSchema = new Schema<IMatchingItem>(
25	  {
26	    id: { type: String, required: true, trim: true },
27	    text: { type: String, required: true, trim: true }
28	  },
29	  { _id: false }
30	);
31	
32	const QuestionSchema = new Schema<IQuestion>(
33	  {
34	    questionType: {
35	      type: String,
36	      enum: [...ENT_QUESTION_TYPES],
37	      default: 'single_choice'
38	    },
39	    questionText: {
40	      type: String,
41	      required: true,
42	      trim: true,
43	      minlength: 5,
44	      maxlength: 2000
45	    },
46	    options: [{ type: String, trim: true }],
47	    correctOption: { type: String, trim: true },
48	    correctOptions: [{ type: String, trim: true }],
49	    matchingLeft: [MatchingItemSchema],
50	    matchingRight: [MatchingItemSchema],
51	    correctMatching: { type: Schema.Types.Mixed },
52	    acceptableAnswers: [{ type: String, trim: true }],
53	    acceptableKeywords: [{ type: String, trim: true }],
54	    referenceAnswer: { type: String, trim: true },
55	    aiExplanation: {
56	      type: String,
57	      required: true,
58	      trim: true,
59	      maxlength: 1200
60	    },
61	    relatedContent: {
62	      type: RelatedContentSchema,
63	      required: true
64	    }
65	  },
66	  { _id: false }
67	);
68	
69	type ITestDocument = Document & Omit<ITest, '_id'>;
70	
71	const TestSchema = new Schema<ITestDocument>(
72	  {
73	    subjectId: {
74	      type: Schema.Types.ObjectId,
75	      ref: 'Subject',
76	      required: true,
77	      index: true
78	    },
79	    bookId: {
80	      type: Schema.Types.ObjectId,
81	      required: true,
82	      index: true
83	    },
84	    chapterId: {
85	      type: Schema.Types.ObjectId,
86	      index: true
87	    },
88	    questions: [QuestionSchema],
89	    sourceContentHash: {
90	      type: String,
91	      required: true,
92	      index: true
93	    },
94	    testProfile: {
95	      type: String,
96	      enum: ['regular', 'ent'],
97	      default: 'ent'
98	    }
99	  },
100	  {
101	    timestamps: true,
102	    collection: 'tests'
103	  }
104	);
105	
106	TestSchema.index({ subjectId: 1, bookId: 1, chapterId: 1, sourceContentHash: 1, testProfile: 1 });
107	TestSchema.index({ createdAt: -1 });
108	
109	TestSchema.path('questions').validate(
110	  (questions: IQuestion[]) => {
111	    if (!Array.isArray(questions) || questions.length !== 10) return false;
112	    try {
113	      questions.forEach((q, i) => {
114	        validateEntQuestion(q as unknown, i);
115	      });
116	      return true;
117	    } catch {
118	      return false;
119	    }
120	  },
121	  'Тест должен содержать ровно 10 корректных вопросов в формате ЕНТ'
122	);
123	
124	TestSchema.statics.findCachedTest = async function (
125	  subjectId: string,
126	  bookId: string,
127	  chapterId: string | undefined,
128	  sourceContentHash: string
129	) {
130	  const query: Record<string, unknown> = {
131	    subjectId,
132	    bookId,
133	    sourceContentHash
134	  };
135	
136	  if (chapterId) {
137	    query.chapterId = chapterId;
138	  } else {
139	    query.chapterId = { $exists: false };
140	  }
141	
142	  return this.findOne(query).sort({ createdAt: -1 });
143	};
144	
145	TestSchema.methods.getQuestionHashes = function (): string[] {
146	  return this.questions.map((q: IQuestion) => Buffer.from(q.questionText).toString('base64'));
147	};
148	
149	export const Test: Model<ITestDocument> = mongoose.model<ITestDocument>('Test', TestSchema);
