69	  private calculateSoloQuestionScore(isCorrect: boolean, responseTimeMs?: number): number {
70	    if (!isCorrect) return 0;
71	    const limitMs = TestController.SOLO_QUESTION_TIME_LIMIT_SEC * 1000;
72	    const safeMs = typeof responseTimeMs === 'number' && Number.isFinite(responseTimeMs) ? responseTimeMs : limitMs;
73	    const remainingSec = Math.max(0, (limitMs - Math.max(0, safeMs)) / 1000);
74	    const score = 1000 * (0.3 + 0.7 * (remainingSec / TestController.SOLO_QUESTION_TIME_LIMIT_SEC));
75	    return Math.round(score);
76	  }
