39	/**
40	 * TEST RESULT SERVICE
41	 * Декомпозиция «тяжёлого» разбора теста на независимые куски:
42	 *  - buildResultSummary   — лёгкая сводка (без обращения к Subject/AI);
43	 *  - buildBreakdown       — по-вопросный разбор + «Темы для повторения» (1 запрос к Subject, без AI);
44	 *  - buildAiExplanation   — AI-feedback (ленивый, дорогой).
45	 *
46	 * Ответы (answers) выравниваются на вопросы теста по тексту вопроса — устойчиво к порядку.
47	 */
48	class TestResultService {
49	  /** Лёгкая сводка по результату — без обращения к БД. */
50	  buildResultSummary(entry: {
51	    _id?: unknown;
52	    testId?: unknown;
53	    subjectId?: unknown;
54	    result: ITestResult;
55	    createdAt?: Date;
56	  }): {
57	    testHistoryId: string | undefined;
58	    testId: string | undefined;
59	    subjectId: string | undefined;
60	    result: ITestResult;
61	    createdAt: Date | undefined;
62	  } {
63	    return {
64	      testHistoryId: entry._id ? String(entry._id) : undefined,
65	      testId: entry.testId ? String(entry.testId) : undefined,
66	      subjectId: entry.subjectId ? String(entry.subjectId) : undefined,
67	      result: entry.result,
68	      createdAt: entry.createdAt
69	    };
70	  }
71	
72	  /** По-вопросный разбор + темы для повторения. Один запрос к Subject, без AI. */
73	  async buildBreakdown(
74	    test: TestLike,
75	    answers: IUserAnswer[]
76	  ): Promise<{
77	    detailedAnswers: Array<Record<string, unknown>>;
78	    topicsToReview: ITopicToReview[];
79	  }> {
80	    const ctx = await this.resolveContext(test);
81	    const byText = this.indexAnswersByQuestion(answers);
82	
83	    // accumulate per-topic correctness across ВСЕ вопросы темы
84	    const perTopic = new Map<string, { title: string; total: number; wrong: number }>();
85	
86	    const detailedAnswers = test.questions.map((q) => {
87	      const ua = byText.get(q.questionText);
88	      const topicId = q.relatedContent?.topicId ? String(q.relatedContent.topicId) : undefined;
89	      const topicTitle = topicId ? ctx.topicTitleById.get(topicId) : undefined;
90	      const isCorrect = ua?.isCorrect ?? false;
91	
92	      if (topicId && topicTitle) {
93	        const acc = perTopic.get(topicId) ?? { title: topicTitle, total: 0, wrong: 0 };
94	        acc.total += 1;
95	        if (!isCorrect) acc.wrong += 1;
96	        perTopic.set(topicId, acc);
97	      }
98	
99	      return {
100	        questionType: getQuestionType(q),
101	        questionText: q.questionText,
102	        options: q.options ?? [],
103	        correctOption: formatExpectedAnswer(q),
104	        selectedOption: ua?.selectedOption ?? '',
105	        isCorrect,
106	        explanation: q.aiExplanation,
107	        relatedContent: { ...q.relatedContent, topicTitle },
108	        matchingLeft: q.matchingLeft,
109	        matchingRight: q.matchingRight
110	      };
111	    });
112	
113	    const topicsToReview: ITopicToReview[] = [...perTopic.entries()]
114	      .filter(([, acc]) => acc.wrong > 0)
115	      .map(([topicId, acc]) => ({
116	        topicId,
117	        topicTitle: acc.title,
118	        totalCount: acc.total,
119	        wrongCount: acc.wrong,
120	        scorePercent: Math.round(((acc.total - acc.wrong) / acc.total) * 100)
121	      }))
122	      .sort((a, b) => a.scorePercent - b.scorePercent);
123	
124	    return { detailedAnswers, topicsToReview };
125	  }
126	
127	  /** Темы для повторения отдельно (без полного разбора) — на случай лёгкого запроса. */
128	  async buildTopicsToReview(test: TestLike, answers: IUserAnswer[]): Promise<ITopicToReview[]> {
129	    const { topicsToReview } = await this.buildBreakdown(test, answers);
130	    return topicsToReview;
131	  }
132	
133	  /** AI-feedback (summary + mistakes). Дорогой: дергает aiService.analyzeAnswers. */
134	  async buildAiExplanation(test: TestLike, answers: IUserAnswer[]): Promise<IAIFeedback> {
135	    const ctx = await this.resolveContext(test);
136	    const byText = this.indexAnswersByQuestion(answers);
137	
138	    const correctAnswers = test.questions.map((q) => {
139	      const topicId = q.relatedContent?.topicId ? String(q.relatedContent.topicId) : undefined;
140	      const topicTitle = topicId ? ctx.topicTitleById.get(topicId) : undefined;
141	      return {
142	        question: q.questionText,
143	        correctSummary: formatExpectedAnswer(q),
144	        explanation: q.aiExplanation,
145	        relatedContent: { ...q.relatedContent, topicTitle }
146	      };
147	    });
148	
149	    // выравниваем ответы строго по порядку вопросов (analyzeAnswers матчит по индексу)
150	    const alignedAnswers: IUserAnswer[] = test.questions.map((q) => {
151	      const ua = byText.get(q.questionText);
152	      return ua ?? { question: q.questionText, selectedOption: '', isCorrect: false };
153	    });
154	
155	    return aiService.analyzeAnswers(correctAnswers, alignedAnswers, {
156	      subjectTitle: ctx.subjectTitle,
157	      bookTitle: ctx.bookTitle,
158	      chapterTitle: ctx.chapterTitle,
159	      topics: ctx.chapterTopicTitles
160	    });
161	  }
162	
163	  /** Что считать «слабой» темой при ручной фильтрации (любая ошибка ниже порога mastery). */
164	  get reviewThresholdPercent(): number {
165	    return ROADMAP_MASTERY_THRESHOLD_PERCENT;
166	  }
167	
168	  // ==================== private ====================
169	
170	  private indexAnswersByQuestion(answers: IUserAnswer[]): Map<string, IUserAnswer> {
171	    const m = new Map<string, IUserAnswer>();
172	    for (const a of answers) m.set(a.question, a);
173	    return m;
174	  }
175	
176	  /** Загрузить Subject и собрать заголовки тем (topicId -> title) для книги/главы теста. */
177	  private async resolveContext(test: TestLike): Promise<ResolvedContext> {
178	    const subject = await Subject.findById(String(test.subjectId)).lean();
179	    if (!subject) {
180	      return {
181	        subjectTitle: '',
182	        bookTitle: '',
183	        chapterTopicTitles: [],
184	        topicTitleById: new Map()
185	      };
186	    }
187	
188	    const book = (subject.books || []).find((b: any) => String(b._id) === String(test.bookId));
189	    const chapter = test.chapterId
190	      ? book?.chapters?.find((c: any) => String(c._id) === String(test.chapterId))
191	      : undefined;
192	
193	    const topicTitleById = new Map<string, string>();
194	    const chapters = chapter ? [chapter] : book?.chapters ?? [];
195	    for (const c of chapters) {
196	      for (const t of c.topics ?? []) {
197	        if (t?._id && t?.title) topicTitleById.set(String(t._id), t.title);
198	      }
199	    }
200	
201	    return {
202	      subjectTitle: subject.title || '',
203	      bookTitle: book?.title || '',
204	      chapterTitle: chapter?.title,
205	      chapterTopicTitles: (chapter?.topics ?? []).map((t: any) => t.title).filter(Boolean),
206	      topicTitleById
207	    };
208	  }
209	}
