18	export function normText(s: string): string {
19	  return s.trim().toLowerCase().replace(/\s+/g, ' ');
20	}
21	
22	function uniqStrings(arr: string[]): string[] {
23	  const seen = new Set<string>();
24	  const out: string[] = [];
25	  for (const x of arr) {
26	    const k = x.trim();
27	    if (!seen.has(k)) {
28	      seen.add(k);
29	      out.push(x.trim());
30	    }
31	  }
32	  return out;
33	}
34	
35	function setsEqualStrings(a: string[], b: string[]): boolean {
36	  if (a.length !== b.length) return false;
37	  const sa = [...a].map(normText).sort();
38	  const sb = [...b].map(normText).sort();
39	  return sa.every((v, i) => v === sb[i]);
40	}
