280	/** Проверка и нормализация одного вопроса после парсинга JSON от LLM */
281	export function validateEntQuestion(q: unknown, index: number): IQuestion {
282	  const o = q as Record<string, unknown>;
283	  const qt = (o.questionType as EntQuestionType) || 'single_choice';
284	  assert(ENT_QUESTION_TYPES.includes(qt), `Вопрос ${index + 1}: неверный questionType`);
285	
286	  const questionText = String(o.questionText ?? '').trim();
287	  assert(questionText.length >= 5, `Вопрос ${index + 1}: слишком короткий questionText`);
288	
289	  const aiExplanation = pickAiExplanation(o);
290	
291	  const rc = (o.relatedContent as Record<string, unknown>) || {};
292	  const pages = Array.isArray(rc.pages) ? rc.pages.map((p) => Number(p)).filter((n) => !Number.isNaN(n)) : [];
293	  const relatedContent = {
294	    pages: pages.length ? pages : [1],
295	    topicTitle: rc.topicTitle != null ? String(rc.topicTitle) : undefined
296	  } as IQuestion['relatedContent'];
297	
298	  const base: IQuestion = {
299	    questionType: qt,
300	    questionText,
301	    aiExplanation,
302	    relatedContent
303	  };
304	
305	  if (qt === 'single_choice') {
306	    const options = (o.options as string[])?.map((x) => String(x).trim()).filter(Boolean) ?? [];
307	    assert(options.length >= 4 && options.length <= 5, `Вопрос ${index + 1}: single_choice — 4–5 вариантов`);
308	    const correctOption = String(o.correctOption ?? '').trim();
309	    assert(options.includes(correctOption), `Вопрос ${index + 1}: correctOption должен быть из options`);
310	    return { ...base, options, correctOption };
311	  }
312	
313	  if (qt === 'multiple_choice') {
314	    const options = (o.options as string[])?.map((x) => String(x).trim()).filter(Boolean) ?? [];
315	    /** 4–10: как single_choice, модель иногда даёт ровно 4 варианта */
316	    assert(
317	      options.length >= 4 && options.length <= 10,
318	      `Вопрос ${index + 1}: multiple_choice — от 4 до 10 вариантов (сейчас ${options.length})`
319	    );
320	    const correctOptions = ((o.correctOptions as string[]) ?? []).map((x) => String(x).trim()).filter(Boolean);
321	    assert(correctOptions.length >= 2, `Вопрос ${index + 1}: минимум 2 правильных варианта`);
322	    assert(correctOptions.every((c) => options.includes(c)), `Вопрос ${index + 1}: correctOptions ⊆ options`);
323	    return { ...base, options, correctOptions: uniqStrings(correctOptions) };
324	  }
325	
326	  if (qt === 'matching_single') {
327	    const matchingLeft = (o.matchingLeft as IMatchingItem[]) ?? [];
328	    const matchingRight = (o.matchingRight as IMatchingItem[]) ?? [];
329	    validateMatchingItems('matchingLeft', matchingLeft, 3, 5);
330	    validateMatchingItems('matchingRight', matchingRight, 3, 6);
331	    const correctMatching = o.correctMatching as Record<string, string>;
332	    assert(correctMatching && typeof correctMatching === 'object', `Вопрос ${index + 1}: нужен correctMatching`);
333	    const leftIds = matchingLeft.map((x) => x.id);
334	    assert(
335	      leftIds.every((id) => typeof correctMatching[id] === 'string'),
336	      `Вопрос ${index + 1}: для каждого left id нужна пара в correctMatching`
337	    );
338	    const rightIds = matchingRight.map((x) => x.id);
339	    const usedRight: string[] = [];
340	    for (const lid of leftIds) {
341	      const rid = correctMatching[lid];
342	      assert(rightIds.includes(rid), `Вопрос ${index + 1}: значение correctMatching должно быть id из matchingRight`);
343	      usedRight.push(rid);
344	    }
345	    assert(
346	      uniqStrings(usedRight).length === usedRight.length,
347	      `Вопрос ${index + 1}: matching_single — каждый правый вариант не более одного раза`
348	    );
349	    return { ...base, matchingLeft, matchingRight, correctMatching };
350	  }
351	
352	  if (qt === 'matching_multiple') {
353	    const matchingLeft = (o.matchingLeft as IMatchingItem[]) ?? [];
354	    const matchingRight = (o.matchingRight as IMatchingItem[]) ?? [];
355	    /** Левая колонка 2–5; правая 3–10 — LLM часто даёт 3 пункта справа */
356	    validateMatchingItems('matchingLeft', matchingLeft, 2, 5);
357	    validateMatchingItems('matchingRight', matchingRight, 3, 10);
358	    const correctMatching = o.correctMatching as Record<string, string[]>;
359	    assert(
360	      correctMatching && typeof correctMatching === 'object' && !Array.isArray(correctMatching),
361	      `Вопрос ${index + 1}: нужен correctMatching`
362	    );
363	    const leftIds = matchingLeft.map((x) => x.id);
364	    const rightIds = matchingRight.map((x) => x.id);
365	    for (const lid of leftIds) {
366	      const arr = correctMatching[lid];
367	      assert(Array.isArray(arr) && arr.length >= 1, `Вопрос ${index + 1}: для ${lid} нужен непустой массив правых id`);
368	      assert(arr.every((rid) => typeof rid === 'string' && rightIds.includes(rid)), `Вопрос ${index + 1}: неверные right id`);
369	    }
370	    return { ...base, matchingLeft, matchingRight, correctMatching };
371	  }
372	
373	  if (qt === 'short_answer') {
374	    const acceptableAnswers = ((o.acceptableAnswers as string[]) ?? []).map((x) => String(x).trim()).filter(Boolean);
375	    assert(acceptableAnswers.length >= 1, `Вопрос ${index + 1}: short_answer — нужен acceptableAnswers`);
376	    return { ...base, acceptableAnswers: uniqStrings(acceptableAnswers) };
377	  }
378	
379	  if (qt === 'text_input') {
380	    const acceptableAnswers = ((o.acceptableAnswers as string[]) ?? []).map((x) => String(x).trim()).filter(Boolean);
381	    const acceptableKeywords = ((o.acceptableKeywords as string[]) ?? []).map((x) => String(x).trim()).filter(Boolean);
382	    const referenceAnswer = o.referenceAnswer != null ? String(o.referenceAnswer).trim() : '';
383	    assert(
384	      acceptableAnswers.length > 0 || acceptableKeywords.length > 0 || referenceAnswer.length > 0,
385	      `Вопрос ${index + 1}: text_input — укажите acceptableAnswers, acceptableKeywords или referenceAnswer`
386	    );
387	    return {
388	      ...base,
389	      acceptableAnswers: acceptableAnswers.length ? uniqStrings(acceptableAnswers) : undefined,
390	      acceptableKeywords: acceptableKeywords.length ? uniqStrings(acceptableKeywords) : undefined,
391	      referenceAnswer: referenceAnswer || undefined
392	    };
393	  }
394	
395	  return base;
396	}
