398	export function parseAndValidateEntQuestions(questions: unknown): IQuestion[] {
399	  if (!Array.isArray(questions)) {
400	    throw new Error('OpenAI response: поле questions отсутствует или не массив.');
401	  }
402	  if (questions.length !== 10) {
403	    throw new Error(
404	      `OpenAI response: ожидалось ровно 10 вопросов, получено ${questions.length}. Проверьте промпт и повторите запрос.`
405	    );
406	  }
407	  return questions.map((q, i) => validateEntQuestion(q, i));
408	}
