410	/** Обычный тест: N× single_choice, ровно 4 варианта (N по запросу, по умолчанию 10) */
411	export function parseAndValidateRegularQuestions(questions: unknown, expectedCount = 10): IQuestion[] {
412	  if (!Array.isArray(questions)) {
413	    throw new Error('OpenAI response: поле questions отсутствует или не массив.');
414	  }
415	  if (questions.length !== expectedCount) {
416	    throw new Error(
417	      `Обычный тест: ожидалось ровно ${expectedCount} вопросов, получено ${questions.length}.`
418	    );
419	  }
420	  return questions.map((raw, index) => {
421	    const o = raw as Record<string, unknown>;
422	    const questionText = String(o.questionText ?? '').trim();
423	    assert(questionText.length >= 5, `Вопрос ${index + 1}: слишком короткий questionText`);
424	    const options = (o.options as string[])?.map((x) => String(x).trim()).filter(Boolean) ?? [];
425	    assert(options.length === 4, `Вопрос ${index + 1}: нужно ровно 4 варианта ответа`);
426	    const correctOption = String(o.correctOption ?? '').trim();
427	    assert(options.includes(correctOption), `Вопрос ${index + 1}: correctOption должен совпадать с одним из options`);
428	    const aiExplanation = pickAiExplanation(o);
429	    const rc = (o.relatedContent as Record<string, unknown>) || {};
430	    const pages = Array.isArray(rc.pages) ? rc.pages.map((p) => Number(p)).filter((n) => !Number.isNaN(n)) : [];
431	    const relatedContent: IRelatedContent = {
432	      pages: pages.length ? pages : [1],
433	      topicTitle: rc.topicTitle != null ? String(rc.topicTitle) : undefined
434	    };
435	    return {
436	      questionType: 'single_choice',
437	      questionText,
438	      options,
439	      correctOption,
440	      aiExplanation,
441	      relatedContent
442	    };
443	  });
444	}

